(function($){const $carousel=$("#carousel-home .owl-carousel");if(!$carousel.length){return}const totalSlides=$carousel.children().length;const enableLoop=totalSlides>1;const $prevBtn=$("#carousel-home .techstore-carousel-prev");const $nextBtn=$("#carousel-home .techstore-carousel-next");const $owlCarousel=$carousel.owlCarousel({items:1,loop:enableLoop,nav:!1,dots:!0,smartSpeed:550,autoplay:totalSlides>1,autoplayTimeout:5000,autoplayHoverPause:!0,responsive:{0:{dots:!1},767:{dots:!1},768:{dots:!0}}});function updateNavState(e){if(enableLoop){$prevBtn.removeClass("is-disabled");$nextBtn.removeClass("is-disabled");return}const index=e&&e.item?e.item.index:0;const count=e&&e.item?e.item.count:totalSlides;$prevBtn.toggleClass("is-disabled",index<=0);$nextBtn.toggleClass("is-disabled",index>=count-1)}$prevBtn.on("click",function(){if($(this).hasClass("is-disabled")){return}$carousel.trigger("prev.owl.carousel")});$nextBtn.on("click",function(){if($(this).hasClass("is-disabled")){return}$carousel.trigger("next.owl.carousel")});$carousel.on("initialized.owl.carousel refreshed.owl.carousel changed.owl.carousel translated.owl.carousel",function(e){setTimeout(function(){$("#carousel-home .owl-carousel .owl-item.active .owl-slide-animated").addClass("is-transitioned"),$("section").show(),updateNavState(e)},40)});$owlCarousel.on("changed.owl.carousel",function(e){$(".owl-slide-animated").removeClass("is-transitioned"),$(".owl-item").eq(e.item.index).find(".owl-slide-animated").addClass("is-transitioned"),updateNavState(e)});setTimeout(function(){updateNavState({item:{index:0,count:totalSlides}})},80)})(jQuery);
